# Category: graphql_security

from graphene import Mutation, String, Int, Enum, ObjectType, relay
from graphene_django import DjangoObjectType
from django.contrib.auth.models import User
from django.conf import settings

class UserType(DjangoObjectType):
    class Meta:
        model = User
        fields = ('id', 'username', 'email', 'bio', 'role', 'is_admin', 'credits', 'subscription_tier')

class UpdateUser(Mutation):
    user = UserType()
    username_changed = String()
    email_changed = String()
    bio_changed = String()
    role_changed = String()
    is_admin_changed = Boolean()
    credits_changed = Int()
    subscription_tier_changed = Enum(SubscriptionTier)

    class Arguments:
        id = relay.GlobalID(description="The user ID")
        username = String(required=False, description="New username for the user")
        email = String(required=False, description="New email for the user")
        bio = String(required=False, description="New bio for the user")
        role = Enum(Role, required=False, description="New role for the user")
        is_admin = Boolean(required=False, description="Toggle admin status for the user")
        credits = Int(required=False, description="New credits for the user")
        subscription_tier = Enum(SubscriptionTier, required=False, description="New subscription tier for the user")

    def mutate(root, info, id, **kwargs):
        user = User.objects.get(id=id)
        original_values = {k: getattr(user, k) for k in kwargs}
        user.update(**{k: v for k, v in kwargs.items() if v is not None})
        changed_values = {k: v != original_values[k] for k, v in user.__dict__.items() if k in original_values}
        return UpdateUser(user=user, **{f"{k}_changed" : v for k, v in changed_values.items()})

class Query(ObjectType):
    user = relay.Node.Field(UserType)

schema = Schema(query=Query, mutation=UpdateUser)